mapper.select:
select
    r.record_id, r.user_id, r.ops_unit_id, r.ent_code, r.out_put_id, r.punch_time_in, r.punch_location_in, r.punch_time_out, r.punch_location_out,
    r.punch_duration, r.assistant, r.assistant_remark, u1.user_name, u1.nick_name, ext.unit_name as ops_unit_name, e.ent_name, o.out_put_code, o.out_put_name,
    u2.user_name as assistant_name, u2.nick_name as assistant_nick
from t_ops_att_record r
left join t_bas_enterprise e on e.ent_code = r.ent_code
left join t_ent_out_put_info o on o.out_put_id = r.out_put_id
left join sys_user u1 on u1.user_id = r.user_id
left join sys_user u2 on u2.user_id = r.assistant
left join t_ext_unit_lib ext on ext.unit_code = r.ops_unit_id


        and r.user_id = #{userId}



            and r.ent_code = #{entCode}


            and r.ent_code in

                #{entCode}




        and (e.region = #{region} or e.region like CONCAT(#{region}, ',%'))


        and r.out_put_id = #{outPutId}


        and r.ops_unit_id = #{opsUnitId}


        and r.punch_time_in between #{punchTimeStart} and #{punchTimeEnd}


order by r.record_id desc
